query:
CALL gds.graph.project(
  'medicalGraph',
  ['Penyakit', 'Gejala', 'Obat', 'Treatment', 'Kategori'], // Semua label
  {
    MEMILIKI_GEJALA: {orientation: 'UNDIRECTED'},
    DIOBATI_DENGAN: {orientation: 'UNDIRECTED'},
    DITREATMENT_DENGAN: {orientation: 'UNDIRECTED'},
    TERMASUK_KATEGORI: {orientation: 'UNDIRECTED'}
  }
)

CALL gds.graph.project(
  'symptomGraph',         // Nama proyeksi baru
  ['Penyakit', 'Gejala'],    // Hanya label tertentu yang dipilih
  {
    MEMILIKI_GEJALA: {       // Relasi yang menghubungkan kedua label tersebut
      orientation: 'UNDIRECTED'
    }
  }
)

CALL gds.graph.project(
  'treatmentGraph',
  ['Penyakit', 'Treatment'],
  {
    DITREATMENT_DENGAN: {orientation: 'UNDIRECTED'}
  }
)

CALL gds.graph.project(
  'categoryGraph',
  ['Penyakit', 'Kategori'],
  {
    TERMASUK_KATEGORI: {orientation: 'UNDIRECTED'}
  }
)

CALL gds.graph.project(
  'medicineGraph',
  ['Penyakit', 'Obat'],
  {
    DIOBATI_DENGAN: {orientation: 'UNDIRECTED'}
  }
)

CALL gds.graph.project(
  'medicineSymptomGraph',
  ['Obat', 'Penyakit', 'Gejala'],
  {
    DIOBATI_DENGAN: {orientation: 'UNDIRECTED'},
    MEMILIKI_GEJALA: {orientation: 'UNDIRECTED'}
  }
)

CALL gds.fastRP.mutate(
    'medicineSymptomGraph',
    {
        embeddingDimension: 64,
        iterationWeights: [0.0, 1.0, 1.0],
        randomSeed: 42,
        mutateProperty: 'embedding'
    }
)
YIELD nodePropertiesWritten, computeMillis
RETURN nodePropertiesWritten, computeMillis;

CALL gds.louvain.write('medicalGraph', {
  writeProperty: 'clusterId'
})
YIELD communityCount, modularity
RETURN communityCount, modularity;

CALL gds.nodeSimilarity.write('medicalGraph', {
  writeRelationshipType: 'MIRIP_DENGAN',
  writeProperty: 'similarity'
})
YIELD nodesCompared, relationshipsWritten
RETURN nodesCompared, relationshipsWritten;
